import{_ as a,a as t,b as s,c as i,d as n,e as o}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as l,o as d,c as r,a2 as p}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"IP Geolocation နှင့် User Management","description":"","frontmatter":{},"headers":[],"relativePath":"my/Other/ip-geolocation-and-user-management.md","filePath":"my/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),c={name:"my/Other/ip-geolocation-and-user-management.md"};function u(g,e,h,m,b,f){return d(),r("div",null,[...e[0]||(e[0]=[p('<h1 id="ip-geolocation-နှင့်-user-management" tabindex="-1">IP Geolocation နှင့် User Management <a class="header-anchor" href="#ip-geolocation-နှင့်-user-management" aria-label="Permalink to &quot;IP Geolocation နှင့် User Management&quot;">​</a></h1><p>IP geolocation က uploader records, login devices နဲ့ logs ဆင်တူတွေထဲက IP addresses တွေကို approximate locations အဖြစ်ပြောင်းပေးပါတယ်။</p><p>configure ပြီးနောက် admin panel က upload နဲ့ access origins တွေကိုပိုရှင်းရှင်းပြနိုင်ပါတယ်။ User Management ကလည်း suspicious IP addresses အတွက် upload access ကို block သို့မဟုတ် restore လုပ်နိုင်စေပါတယ်။</p><h2 id="ဘယ်နေရာမှာ-configure-လုပ်မလဲ" tabindex="-1">ဘယ်နေရာမှာ Configure လုပ်မလဲ <a class="header-anchor" href="#ဘယ်နေရာမှာ-configure-လုပ်မလဲ" aria-label="Permalink to &quot;ဘယ်နေရာမှာ Configure လုပ်မလဲ&quot;">​</a></h2><p>ဖွင့်ပါ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; IP Geolocation</span></span></code></pre></div><p><img src="'+a+`" alt="IP geolocation" loading="lazy"></p><h2 id="available-settings" tabindex="-1">Available Settings <a class="header-anchor" href="#available-settings" aria-label="Permalink to &quot;Available Settings&quot;">​</a></h2><p>IP geolocation flow အသစ်က map service တစ်ခုတည်းပေါ်မမှီခိုဘဲ sources အများကြီး support လုပ်ပါတယ်။</p><table tabindex="0"><thead><tr><th>Setting</th><th>Purpose</th></tr></thead><tbody><tr><td>IP geolocation language</td><td>display language ရွေးရန်၊ ဥပမာ English, Simplified Chinese, Japanese, French စသည်။</td></tr><tr><td>MaxMind Account ID</td><td>MaxMind GeoLite Web Service အတွက် MaxMind account ID။</td></tr><tr><td>MaxMind License Key</td><td>MaxMind License Key။</td></tr><tr><td>Tencent Map Key</td><td>Tencent Location Service key။ Chinese addresses နဲ့ mainland China IPs အတွက်အသုံးဝင်သည်။</td></tr><tr><td>ipapi Key</td><td>APILayer ipapi key။ multilingual IP geolocation support လုပ်သည်။</td></tr></tbody></table><p>လိုအပ်တဲ့ services တွေကိုသာဖြည့်ပါ။ field အားလုံး configure လုပ်ဖို့မလိုပါ။</p><p>key မထည့်လည်း ImgBed က built-in free sources တွေကိုကြိုးစားသုံးပါမယ်။ ဒါပေမယ့် stability, language support, precision က သင်ကိုယ်တိုင် configure လုပ်ထားတဲ့ service ထက်နည်းနိုင်ပါတယ်။</p><h2 id="recommended-choices" tabindex="-1">Recommended Choices <a class="header-anchor" href="#recommended-choices" aria-label="Permalink to &quot;Recommended Choices&quot;">​</a></h2><p>Chinese addresses အဓိကလိုလျှင်:</p><ol><li>IP geolocation language ကို Simplified Chinese ထားပါ။</li><li>Tencent Map Key configure လုပ်ပါ။</li><li>optional အနေနဲ့ MaxMind သို့မဟုတ် ipapi ကို fallback source အဖြစ်ထည့်ပါ။</li></ol><p>English သို့မဟုတ် multilingual addresses အဓိကလိုလျှင်:</p><ol><li>လိုအပ်တဲ့ language ရွေးပါ။</li><li>MaxMind Account ID နဲ့ License Key configure လုပ်ပါ။</li><li>multilingual results ပိုကောင်းချင်လျှင် ipapi Key ထည့်ပါ။</li></ol><h2 id="maxmind-setup" tabindex="-1">MaxMind Setup <a class="header-anchor" href="#maxmind-setup" aria-label="Permalink to &quot;MaxMind Setup&quot;">​</a></h2><p>MaxMind အတွက်လိုအပ်တာ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>MaxMind dashboard မှာ account ID ရှာပြီး License Keys page မှ License Key generate လုပ်ပါ။</p><p><img src="`+t+'" alt="MaxMind key config" loading="lazy"></p><p>generation ပြီးနောက် Account ID နဲ့ License Key ကို ImgBed ထဲ paste လုပ်ပြီး save လုပ်ပါ။</p><p>MaxMind free plan ကနေ့စဉ်အသုံးအတွက်သင့်တော်ပေမယ့် request limits ရှိပါတယ်။ quota ကျော်လျှင် ImgBed က အခြား available sources တွေကိုဆက်ကြိုးစားပါမယ်။</p><h2 id="ipapi-setup" tabindex="-1">ipapi Setup <a class="header-anchor" href="#ipapi-setup" aria-label="Permalink to &quot;ipapi Setup&quot;">​</a></h2><p>ipapi က APILayer API Key ကိုသုံးပါတယ်။</p><p>ipapi console ကိုဖွင့်ပြီး ပြထားတဲ့ API Key ကို copy လုပ်ပါ။</p><p><img src="'+s+'" alt="ipapi config" loading="lazy"></p><p>ImgBed ထဲက <code>ipapi Key</code> field မှာ paste လုပ်ပြီး save လုပ်ပါ။</p><p>ipapi က multilingual IP geolocation ကို support လုပ်ပြီး selected language နဲ့ addresses ပြချင်တဲ့အခါအသုံးဝင်ပါတယ်။ free plan မှာလည်း request limits ရှိပါတယ်။ quota ကုန်လျှင် ImgBed က အခြား available sources တွေကိုဆက်ကြိုးစားပါမယ်။</p><h2 id="tencent-map-key-setup" tabindex="-1">Tencent Map Key Setup <a class="header-anchor" href="#tencent-map-key-setup" aria-label="Permalink to &quot;Tencent Map Key Setup&quot;">​</a></h2><p>Tencent Map Key က Chinese addresses၊ အထူးသဖြင့် mainland China IPs အတွက်အသုံးဝင်ပါတယ်။</p><p>Tencent Location Service မှာ key ဖန်တီးတဲ့အခါ enable လုပ်ပါ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebServiceAPI</span></span></code></pre></div><p>ဖန်တီးပြီးနောက် key ကို <code>Tencent Map Key</code> ထဲ paste လုပ်ပြီး save လုပ်ပါ။</p><p>basic Chinese IP geolocation ပဲလိုလျှင် Tencent Map Key ကစဖို့လုံလောက်ပါတယ်။</p><h2 id="user-management-မှာ-ဘာတွေစစ်မလဲ" tabindex="-1">User Management မှာ ဘာတွေစစ်မလဲ <a class="header-anchor" href="#user-management-မှာ-ဘာတွေစစ်မလဲ" aria-label="Permalink to &quot;User Management မှာ ဘာတွေစစ်မလဲ&quot;">​</a></h2><p>User Management ကို admin panel အပေါ်ပိုင်းကနေဖွင့်နိုင်ပါတယ်။</p><p><img src="'+i+'" alt="User management" loading="lazy"></p><p>User Management က IP အလိုက် upload activity ကိုပြပါတယ်:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>IP source</td><td>uploader source IP။</td></tr><tr><td>Address</td><td>IP မှ resolve လုပ်ထားတဲ့ approximate location။</td></tr><tr><td>Total upload size</td><td>ဒီ IP မှ upload လုပ်ထားတဲ့ total file size။</td></tr><tr><td>Upload count</td><td>ဒီ IP မှ upload အရေအတွက်။</td></tr><tr><td>Upload allowed</td><td>On ဆို uploads allowed ဖြစ်သည်။ Off ဆို uploads blocked ဖြစ်သည်။</td></tr></tbody></table><p>ဘယ်ဘက် arrow ကိုနှိပ်ပြီး အဲဒီ IP မှ uploaded files list ကို expand လုပ်ပါ။</p><p>file list မှာ file name, preview, file size, moderation result, file status, upload time တို့ကိုပြပါတယ်။ uploads တွေ suspicious ဖြစ်လျှင် IP ကိုအရင် expand လုပ်ပြီး files တွေ review လုပ်ကာ နောက်ထပ် uploads block လုပ်မလားဆုံးဖြတ်ပါ။</p><p>IP တစ်ခု suspicious ဖြစ်လျှင် <code>Upload allowed</code> ကို off လုပ်ပါ။ အဲဒီ IP မှ future uploads တွေ blocked ဖြစ်ပါမယ်။</p><h2 id="search-sort-advanced-filters" tabindex="-1">Search, Sort, Advanced Filters <a class="header-anchor" href="#search-sort-advanced-filters" aria-label="Permalink to &quot;Search, Sort, Advanced Filters&quot;">​</a></h2><p>User Management အပေါ်ပိုင်းမှာ IP source သို့မဟုတ် address နဲ့ search လုပ်နိုင်ပါတယ်။</p><p>recent uploaders, high-frequency uploaders, high-usage IPs ကိုရှာဖို့ time, upload count, total upload size နဲ့ sort လုပ်ပါ။</p><p>ပိုပြီးအသေးစိတ်စစ်ဖို့ advanced filters ကိုဖွင့်ပါ။</p><p><img src="'+n+'" alt="Advanced filters" loading="lazy"></p><p>Advanced filters က support လုပ်တာတွေ:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Usage</th></tr></thead><tbody><tr><td>Time range</td><td>selected period အတွင်း files upload လုပ်ခဲ့တဲ့ IPs ပြသည်။</td></tr><tr><td>Access status</td><td>normal, blocked နဲ့ states ဆင်တူများအလိုက် filter လုပ်သည်။</td></tr><tr><td>Allow/block list</td><td>allowlist, blocklist, unset အလိုက် filter လုပ်သည်။</td></tr><tr><td>File type</td><td>images, videos, audio, documents, code, other files upload လုပ်ခဲ့တဲ့ IPs ပြသည်။</td></tr><tr><td>File size</td><td>uploaded file size range အလိုက် filter လုပ်သည်။</td></tr><tr><td>Age rating</td><td>unset, General, R12+, R16+, R18 စတဲ့ ratings အလိုက် filter လုပ်သည်။</td></tr><tr><td>File status</td><td>abnormal files စစ်ရန် current file status အလိုက် filter လုပ်သည်။</td></tr></tbody></table><p>filter apply လုပ်ရန် <code>Apply Filters</code> ကိုနှိပ်ပါ။ data အားလုံးကိုပြန်ကြည့်ရန် <code>Reset</code> ကိုသုံးပါ။</p><h2 id="mobile-view" tabindex="-1">Mobile View <a class="header-anchor" href="#mobile-view" aria-label="Permalink to &quot;Mobile View&quot;">​</a></h2><p>mobile မှာ User Management က card layout အဖြစ်ပြောင်းပါတယ်။</p><p><img src="'+o+`" alt="Mobile user management" loading="lazy"></p><p>card တစ်ခုစီမှာ IP, address, total upload size, upload count, upload allowed switch တို့ကိုပြပါတယ်။ horizontal table scrolling မလိုဘဲ users manage လုပ်နိုင်ပါတယ်။</p><h2 id="location-မှားနေသလိုမြင်ရင်" tabindex="-1">Location မှားနေသလိုမြင်ရင် <a class="header-anchor" href="#location-မှားနေသလိုမြင်ရင်" aria-label="Permalink to &quot;Location မှားနေသလိုမြင်ရင်&quot;">​</a></h2><p>IP geolocation က approximate ဖြစ်ပါတယ်။ precise street address မဟုတ်ပါ။</p><p>user က proxy, data center, cloud server, cross-border network အနောက်မှာရှိလျှင် ပြထားတဲ့ location က real location နဲ့ကွာနိုင်ပါတယ်။</p><p>ဒီ feature ကို rough origin နားလည်ဖို့၊ abnormal uploads ရှာဖို့၊ blocking decisions အတွက်ကူညီဖို့သုံးပါ။ precise tracking အဖြစ်မယူဆပါနှင့်။</p><h2 id="common-cases" tabindex="-1">Common Cases <a class="header-anchor" href="#common-cases" aria-label="Permalink to &quot;Common Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Case</th><th>Meaning</th></tr></thead><tbody><tr><td>Address ဗလာ</td><td>IP မ resolve လုပ်ရသေးတာ သို့မဟုတ် current source unavailable ဖြစ်နိုင်သည်။</td></tr><tr><td>Address language မှား</td><td>IP geolocation language နဲ့ အဲဒီ language support လုပ်တဲ့ source configured ဖြစ်လားစစ်ပါ။</td></tr><tr><td>Address က data center ပြသည်</td><td>proxies, cloud servers, crawlers အများအပြားက data center သို့မဟုတ် ISP addresses အနေနဲ့ပေါ်နိုင်သည်။</td></tr><tr><td>Upload count မြင့်</td><td>ဒီ IP ကိုဂရုတစိုက် review လုပ်ပြီးလိုအပ်လျှင် uploads block လုပ်ပါ။</td></tr><tr><td>Total upload size ကြီး</td><td>sort/filter လုပ်ပါ၊ IP expand လုပ်ပါ၊ specific files စစ်ပါ။</td></tr><tr><td>blocking ပြီးနောက် restore လို</td><td><code>Upload allowed</code> ကိုပြန် on လုပ်ပါ။</td></tr></tbody></table><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Other Settings ထဲက IP Geolocation ဖွင့်ပါ</span></span>
<span class="line"><span>-&gt; IP geolocation language ရွေးပါ</span></span>
<span class="line"><span>-&gt; လိုအပ်သလို MaxMind, Tencent Map, ipapi credentials ဖြည့်ပါ</span></span>
<span class="line"><span>-&gt; settings save လုပ်ပါ</span></span>
<span class="line"><span>-&gt; User Management ဖွင့်ပါ</span></span>
<span class="line"><span>-&gt; IP source, address, total upload size, upload count review လုပ်ပါ</span></span>
<span class="line"><span>-&gt; abnormal IPs ရှာဖို့ search, sort, advanced filters သုံးပါ</span></span>
<span class="line"><span>-&gt; လိုအပ်သလို uploads allow/block လုပ်ပါ</span></span></code></pre></div>`,64)])])}const I=l(c,[["render",u]]);export{v as __pageData,I as default};
